import sysfrom pathlib import Pathimport jsonimport reimport pyarrow.parquet as pqfrom gensim.models import Word2Vec# Ensure project root is on sys.pathPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import PROCESSED_DATA_DIR, EMBEDDINGS_DIR, REPORTS_DIRTEXT_COL = "full_text"MIN_TOKEN_LEN = 2DATASET_TAG = "large_lite"BATCH_SIZE = 256def simple_tokenize(text: str):    text = str(text).lower()    tokens = re.findall(r"[a-zA-Z0-9]+", text)    tokens = [tok for tok in tokens if len(tok) >= MIN_TOKEN_LEN]    return tokensdef get_input_path():    return PROCESSED_DATA_DIR / "train_doc_5d_large_lite.parquet"def get_corpus_path():    return PROCESSED_DATA_DIR / "train_doc_5d_large_lite_corpus.txt"def build_corpus_file(parquet_path: Path, corpus_path: Path):    """    Read parquet in batches, tokenize each document, and write one tokenized    document per line to a plain-text corpus file.    """    parquet_file = pq.ParquetFile(parquet_path)    n_docs = 0    total_tokens = 0    if corpus_path.exists():        corpus_path.unlink()    with corpus_path.open("w", encoding="utf-8") as f_out:        for batch_idx, batch in enumerate(            parquet_file.iter_batches(batch_size=BATCH_SIZE, columns=[TEXT_COL]),            start=1,        ):            texts = batch.column(0).to_pylist()            for text in texts:                tokens = simple_tokenize(text)                if not tokens:                    continue                f_out.write(" ".join(tokens) + "\n")                n_docs += 1                total_tokens += len(tokens)            if batch_idx % 20 == 0:                print(                    f"Processed batches: {batch_idx} | "                    f"documents written: {n_docs:,} | "                    f"tokens: {total_tokens:,}"                )    avg_doc_len = total_tokens / n_docs if n_docs > 0 else 0.0    return n_docs, total_tokens, avg_doc_lendef train_word2vec_model(corpus_path: Path):    """    Train Word2Vec directly from corpus file to reduce memory usage.    """    model = Word2Vec(        corpus_file=str(corpus_path),        vector_size=100,        window=5,        min_count=5,        workers=4,        sg=1,        epochs=5,        seed=42,    )    return modeldef save_outputs(model, n_docs, total_tokens, avg_doc_len, corpus_path: Path):    EMBEDDINGS_DIR.mkdir(parents=True, exist_ok=True)    REPORTS_DIR.mkdir(parents=True, exist_ok=True)    model_path = EMBEDDINGS_DIR / f"word2vec_{DATASET_TAG}.model"    vectors_path = EMBEDDINGS_DIR / f"word2vec_{DATASET_TAG}.kv"    report_path = REPORTS_DIR / f"word2vec_training_summary_{DATASET_TAG}.json"    model.save(str(model_path))    model.wv.save(str(vectors_path))    summary = {        "dataset_tag": DATASET_TAG,        "training_source": "train_doc_5d_large_lite.parquet",        "corpus_file": str(corpus_path),        "n_documents": n_docs,        "total_tokens": total_tokens,        "avg_document_length_tokens": avg_doc_len,        "vocab_size": len(model.wv.key_to_index),        "vector_size": model.vector_size,        "window": model.window,        "min_count": model.min_count,        "sg": model.sg,        "epochs": model.epochs,    }    with open(report_path, "w", encoding="utf-8") as f:        json.dump(summary, f, indent=2)    print("\nSaved outputs:")    print(model_path)    print(vectors_path)    print(report_path)def main():    parquet_path = get_input_path()    corpus_path = get_corpus_path()    print("Building tokenized corpus file from large_lite parquet...")    n_docs, total_tokens, avg_doc_len = build_corpus_file(parquet_path, corpus_path)    print("\nCorpus build completed.")    print(f"Documents written: {n_docs:,}")    print(f"Total tokens:      {total_tokens:,}")    print(f"Avg doc length:    {avg_doc_len:.2f}")    print("\nTraining Word2Vec from corpus file...")    model = train_word2vec_model(corpus_path)    print("\nTraining completed.")    print(f"Vocabulary size: {len(model.wv.key_to_index):,}")    sample_words = ["business", "risk", "market", "company"]    print("\nSample nearest neighbors:")    for word in sample_words:        if word in model.wv:            print(f"\n{word}:")            print(model.wv.most_similar(word, topn=5))        else:            print(f"\n{word}: not in vocabulary")    save_outputs(model, n_docs, total_tokens, avg_doc_len, corpus_path)    print("\nDone.")if __name__ == "__main__":    main()